const BLOG_POSTS = {"welcome": "<!DOCTYPE html><html lang=\"en\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"><title>Welcome to the New Chigbu Law Firm Website — Clifford C. Chigbu, Attorney at Law</title><meta name=\"theme-color\" content=\"#0A1320\"><style>:root{--primary:#0F1B2D;--primary-dark:#0A1320;--accent:#D4A24C;--bg:#0A1320;--text:#F4EFE6;--muted:#9FA8B8;}*{box-sizing:border-box;margin:0;padding:0;}body{background:var(--bg);color:var(--text);font-family:Georgia,serif;line-height:1.6;}a{color:var(--accent);}</style></head><body><main style=\"max-width:720px;margin:0 auto;padding:40px 24px;\"><a href=\"/blog/\" style=\"color:var(--accent);font-family:-apple-system,sans-serif;font-size:13px;\">← All posts</a><h1 style=\"margin:14px 0 8px;font-family:-apple-system,sans-serif;\">Welcome to the New Chigbu Law Firm Website</h1><div style=\"color:var(--muted);font-size:13px;font-family:-apple-system,sans-serif;margin-bottom:24px;\">2026-04-07 · Mr. Chigbu</div><div style=\"color:var(--text);line-height:1.7;\"><p>We&#39;ve redesigned our website to make one thing easier: getting answers, fast.</p>\n<h2>What changed</h2>\n<p>You can now request help <strong>directly from any practice area</strong> below. Tell us a little about your situation, and we&#39;ll be ready before you ever step into the office.</p>\n<h2>What didn&#39;t change</h2>\n<p>Care, attention, and the same phone number you&#39;ve always called: <strong>TBD</strong>.</p>\n<p>If you&#39;d rather just talk to a human, that&#39;s what we prefer too. Pick up the phone any time.</p></div><p style=\"margin-top:40px;\"><a href=\"/\" style=\"color:var(--accent);\">← Back to home</a></p></main></body></html>"};
